import React, { useState } from 'react';
import { apiGet } from '../utils/api';

function SearchBar() {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);

  function handleSearch(e) {
    e.preventDefault();
    const searchTerm = query.trim();
    if (!searchTerm) return;

    // FIX: Eliminated dangerous evaluations entirely
    apiGet("/search?q=" + encodeURIComponent(searchTerm))
      .then(data => setResults(data.results || []))
      .catch(err => console.error(err));
  }

  return (
    <div className="search-bar">
      <h2>Catalog Search Tool</h2>
      <form onSubmit={handleSearch}>
        <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search..." />
        <button type="submit">Execute</button>
      </form>

      <div className="results">
        {results.map((result, index) => (
          <div key={index} className="result-item">
            <h4>{result.title}</h4>
            {/* FIX: Safely render text content without dangerouslySetInnerHTML strings */}
            <div>{result.snippet}</div>
            <span>Price: ${result.price}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default SearchBar;
